import{_ as a,o as n,c as e,a3 as i}from"./chunks/framework.CqFBhNnV.js";const b=JSON.parse('{"title":"Git Commit 风格指南","description":"","frontmatter":{"title":"Git Commit 风格指南","order":140},"headers":[],"relativePath":"dev/git-commit-style.md","filePath":"dev/git-commit-style.md","lastUpdated":1775469237000}'),p={name:"dev/git-commit-style.md"};function l(t,s,r,c,d,o){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="git-commit-风格指南" tabindex="-1">Git Commit 风格指南 <a class="header-anchor" href="#git-commit-风格指南" aria-label="Permalink to &quot;Git Commit 风格指南&quot;">​</a></h1><p>本文档描述 Fredica 项目的 git commit 消息约定。</p><hr><h2 id="_1-基本格式" tabindex="-1">1. 基本格式 <a class="header-anchor" href="#_1-基本格式" aria-label="Permalink to &quot;1. 基本格式&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;type&gt;(&lt;scope&gt;): &lt;subject&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;body&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>首行</strong>：<code>type(scope): subject</code>，不超过 80 字符</li><li><strong>正文</strong>：按模块分组，每条变更一行，以 <code>- </code> 开头。请勿遗漏任何重大修改（尤其是工具模块的修改），你可以分很多很多模块。</li></ul><hr><h2 id="_2-type-类型" tabindex="-1">2. Type 类型 <a class="header-anchor" href="#_2-type-类型" aria-label="Permalink to &quot;2. Type 类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>type</th><th>用途</th></tr></thead><tbody><tr><td><code>feat</code></td><td>新功能、新模块</td></tr><tr><td><code>fix</code></td><td>Bug 修复</td></tr><tr><td><code>refactor</code></td><td>重构（不改变外部行为）</td></tr><tr><td><code>docs</code></td><td>文档变更</td></tr><tr><td><code>test</code></td><td>测试相关</td></tr><tr><td><code>chore</code></td><td>构建、依赖、配置等杂项</td></tr><tr><td><code>wip</code></td><td>进行中的工作（见下文）</td></tr></tbody></table><hr><h2 id="_3-wip-提交" tabindex="-1">3. wip 提交 <a class="header-anchor" href="#_3-wip-提交" aria-label="Permalink to &quot;3. wip 提交&quot;">​</a></h2><p><strong><code>wip</code> 是本项目最常用的 type 之一。</strong> 开发过程中随时用 <code>wip</code> 暂存进度，不必等到功能完整才提交。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>wip: 移除 PromptGraph 引擎，新增 Torch 版本管理模块</span></span>
<span class="line"><span>wip: WebenSource 分析进度同步（进行中）</span></span>
<span class="line"><span>wip: 前端任务中心重构草稿</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>wip</code> 提交的正文格式与普通提交相同，列出已完成的部分即可，未完成的不必提及。</p><hr><h2 id="_4-scope-作用域" tabindex="-1">4. Scope 作用域 <a class="header-anchor" href="#_4-scope-作用域" aria-label="Permalink to &quot;4. Scope 作用域&quot;">​</a></h2><p>scope 用于快速定位变更范围，可以是模块名、技术层或跨层组合：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(worker): ...</span></span>
<span class="line"><span>fix(python/bilibili): ...</span></span>
<span class="line"><span>refactor(webui): ...</span></span>
<span class="line"><span>feat(executor/kotlin): ...</span></span>
<span class="line"><span>feat(asr+webui): ...          # 跨层用 + 连接</span></span>
<span class="line"><span>refactor(json+error): ...     # 跨关注点用 + 连接</span></span>
<span class="line"><span>docs(dev): ...</span></span>
<span class="line"><span>docs(claude): ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><hr><h2 id="_5-subject-主题行" tabindex="-1">5. Subject 主题行 <a class="header-anchor" href="#_5-subject-主题行" aria-label="Permalink to &quot;5. Subject 主题行&quot;">​</a></h2><ul><li>用中文，简洁描述&quot;做了什么&quot;</li><li>多个并列变更用 <code>+</code> 或 <code>·</code> 连接，不超过 80 字符</li><li>不加句号</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ✅ 好的例子</span></span>
<span class="line"><span>feat(worker): DAG 依赖失败级联取消 + MaterialGetRoute</span></span>
<span class="line"><span>fix(python/bilibili): 修复凭据校验逻辑（check_valid 取反）</span></span>
<span class="line"><span>refactor(webui): 抽取 WorkflowInfoPanel 组件，重构任务状态展示</span></span>
<span class="line"><span>feat(asr+webui): 集成 faster-whisper ASR 支持，重构素材库组件</span></span>
<span class="line"><span></span></span>
<span class="line"><span># ❌ 避免</span></span>
<span class="line"><span>feat: update code</span></span>
<span class="line"><span>feat(worker): 修改了一些东西</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><hr><h2 id="_6-正文格式" tabindex="-1">6. 正文格式 <a class="header-anchor" href="#_6-正文格式" aria-label="Permalink to &quot;6. 正文格式&quot;">​</a></h2><p>正文按<strong>模块</strong>分组，每组一个二级标题（<code>type(scope):</code>），组内每条变更一行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(worker):</span></span>
<span class="line"><span>- Task: 新增 resetStaleTasks()、failOrphanedTasks()</span></span>
<span class="line"><span>- WorkerEngine: start() 改为 suspend，新增 runStartupRecovery()</span></span>
<span class="line"><span>- 新增测试：TaskReconcileTest、WorkflowRunReconcileTest</span></span>
<span class="line"><span></span></span>
<span class="line"><span>feat(weben):</span></span>
<span class="line"><span>- WebenSource: 新增 progress 字段（0-100），DB schema 迁移</span></span>
<span class="line"><span>- WebenSourceAnalyzeRoute: Phase C 完整实现——创建 WorkflowRun + 任务链</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fix(bridge):</span></span>
<span class="line"><span>- MyJsMessageHandler: 修复 kmpJsBridge 回调中单引号导致 JS 语法错误</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>变更描述格式：<code>- &lt;类名/文件名&gt;: &lt;做了什么&gt;</code>，说明具体改动而非泛泛描述。</p><hr><h2 id="_7-大型提交示例" tabindex="-1">7. 大型提交示例 <a class="header-anchor" href="#_7-大型提交示例" aria-label="Permalink to &quot;7. 大型提交示例&quot;">​</a></h2><p>跨多个模块的大型提交，首行用 <code>·</code> 列出主要模块，正文按模块展开：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: 启动恢复系统 + WebenSource 分析流水线 Phase C + Executor 链 + B站凭据 + 知识网络前端</span></span>
<span class="line"><span></span></span>
<span class="line"><span>fix(bridge):</span></span>
<span class="line"><span>- MyJsMessageHandler: 修复 kmpJsBridge 回调中单引号导致 JS 语法错误</span></span>
<span class="line"><span></span></span>
<span class="line"><span>feat(worker):</span></span>
<span class="line"><span>- Task: 新增 resetStaleTasks()、failOrphanedTasks()、snapshotNonTerminalTasks()</span></span>
<span class="line"><span>- WorkerEngine: start() 改为 suspend，新增 runStartupRecovery() 五步恢复序列</span></span>
<span class="line"><span>- RestartTaskLog: 新增数据模型 + DB 实现，记录每次启动恢复日志（可审计）</span></span>
<span class="line"><span>- 新增测试：RestartTaskLogDbTest、TaskReconcileTest、WorkflowRunReconcileTest</span></span>
<span class="line"><span></span></span>
<span class="line"><span>feat(executor/kotlin):</span></span>
<span class="line"><span>- FetchSubtitleExecutor: Bilibili 字幕轨优先，SHA-256 缓存，Whisper ASR 兜底</span></span>
<span class="line"><span>- WebenConceptExtractExecutor: 切块 → PromptGraph → 写 WebenConcept/Relation/Flashcard</span></span>
<span class="line"><span></span></span>
<span class="line"><span>refactor(startup):</span></span>
<span class="line"><span>- main.kt: 修正 runBlocking(Dispatchers.IO) 误用</span></span>
<span class="line"><span>- FredicaApi.jvm.kt: 新增 engineScope 持久化；新增 onAppReady() 启动后台对账</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><hr><h2 id="_8-提交流程" tabindex="-1">8. 提交流程 <a class="header-anchor" href="#_8-提交流程" aria-label="Permalink to &quot;8. 提交流程&quot;">​</a></h2><h3 id="提交前-git-diff-确认变更" tabindex="-1">提交前：git diff 确认变更 <a class="header-anchor" href="#提交前-git-diff-确认变更" aria-label="Permalink to &quot;提交前：git diff 确认变更&quot;">​</a></h3><p>提交前先用 <code>git diff</code> 全面了解本次改动，再据此撰写 commit 消息：</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看所有未暂存的变更</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看已暂存的变更</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cached</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看变更文件列表（快速概览）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stat</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --short</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>通过 diff 确认：变更范围是否与预期一致、有无意外修改、scope 和 subject 是否准确覆盖所有改动。</p><h3 id="一次提交整个暂存区" tabindex="-1">一次提交整个暂存区 <a class="header-anchor" href="#一次提交整个暂存区" aria-label="Permalink to &quot;一次提交整个暂存区&quot;">​</a></h3><p><strong>优先将所有相关变更放在同一个 commit 中提交</strong>，而不是拆成多个小 commit。这样每个 commit 都是一个完整的逻辑单元，便于 <code>git log</code> 追踪和 <code>git revert</code>。</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 暂存所有变更后一次提交</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">1&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;...&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># wip 场景：快速暂存全部</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;wip: ...&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>只有在变更明确属于不同关注点（如同时有功能开发和文档更新）且希望分开追踪时，才考虑拆分提交。</p><hr><h2 id="_9-co-author-行" tabindex="-1">9. Co-Author 行 <a class="header-anchor" href="#_9-co-author-行" aria-label="Permalink to &quot;9. Co-Author 行&quot;">​</a></h2><p>AI 辅助开发的提交在正文末尾加 Co-Author 行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Co-Authored-By: Claude Sonnet 4.6 &lt;noreply@anthropic.com&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,45)])])}const u=a(p,[["render",l]]);export{b as __pageData,u as default};
